import { BrowserRouter as Router, Routes, Route } from 'react'
import React, {useState} from 'react';
import Header from './components/Header';
import Card from './components/Card';
import {product} from './data/products';
import './styles/main.css';


function App() {
    const [cart, setCart] = useState([]);
    const OnAdd = (product) => {
        setCart([...cart, product]);
        console.log("Товар добавлен в корзину:", product.name);
    };

    return (
        <div className="App">
            {/* Передаем количество товаров в корзине */}
            <Header cartCount={cart.length} />

            <main style={{ padding: '40px', display: 'flex', 'gap': '20px', flexWrap: 'wrap', justifyContent: 'center'}}>
                {product.map(item => (
                    <Card key={item.id} product={item} onAdd={OnAdd} />
                ))}
            </main>
        </div>
    );
}

export default App;
